// Templates for Swift plugin files and SPM Package.swift manifests
// generated by `nitrogen link`.

/// iOS `*Plugin.swift` stub — created when the file is missing.
String iosPluginSwiftStub(String className) =>
    '''import Flutter
import UIKit

public class ${className}Plugin: NSObject, FlutterPlugin {
  public static func register(with registrar: FlutterPluginRegistrar) {
    // Nitro registration will be injected here by nitrogen link.
  }
}
''';

/// macOS `*Plugin.swift` stub — created when the file is missing.
String macosPluginSwiftStub(String className) =>
    '''import FlutterMacOS
import Foundation

public class ${className}Plugin: NSObject, FlutterPlugin {
  public static func register(with registrar: FlutterPluginRegistrar) {
    // Nitro registration will be injected here by nitrogen link.
  }
}
''';

/// Flutter 3.41+ SPM `Package.swift` for the iOS platform.
///
/// Creates two targets:
/// - `${className}Cpp` — C++ bridge (compiled as Obj-C++ via `.mm` forwarder)
/// - `$pluginName` — Swift bridge (depends on the C++ target)
String iosPackageSwiftContent(String pluginName, String className) =>
    '// swift-tools-version: 5.9\n'
    'import PackageDescription\n'
    '\n'
    'let package = Package(\n'
    '  name: "$pluginName",\n'
    '  platforms: [.iOS(.v13)],\n'
    '  products: [\n'
    '    .library(name: "${pluginName.replaceAll('_', '-')}", targets: ["$pluginName"])\n'
    '  ],\n'
    '  targets: [\n'
    '    .target(\n'
    '      name: "${className}Cpp",\n'
    '      path: "Sources/${className}Cpp",\n'
    '      publicHeadersPath: "include",\n'
    '      cxxSettings: [\n'
    '        .headerSearchPath("include"),\n'
    '        .unsafeFlags(["-std=c++17"])\n'
    '      ]\n'
    '    ),\n'
    '    .target(\n'
    '      name: "$pluginName",\n'
    '      dependencies: ["${className}Cpp"],\n'
    '      path: "Sources/$className"\n'
    '    )\n'
    '  ]\n'
    ')\n';

/// Flutter 3.41+ SPM `Package.swift` for the macOS platform.
///
/// Mirrors [iosPackageSwiftContent] with a macOS platform constraint.
String macosPackageSwiftContent(String pluginName, String className) =>
    '// swift-tools-version: 5.9\n'
    'import PackageDescription\n'
    '\n'
    'let package = Package(\n'
    '  name: "$pluginName",\n'
    '  platforms: [.macOS(.v10_15)],\n'
    '  products: [\n'
    '    .library(name: "${pluginName.replaceAll('_', '-')}", targets: ["$pluginName"])\n'
    '  ],\n'
    '  targets: [\n'
    '    .target(\n'
    '      name: "${className}Cpp",\n'
    '      path: "Sources/${className}Cpp",\n'
    '      publicHeadersPath: "include",\n'
    '      cxxSettings: [\n'
    '        .headerSearchPath("include"),\n'
    '        .unsafeFlags(["-std=c++17"])\n'
    '      ]\n'
    '    ),\n'
    '    .target(\n'
    '      name: "$pluginName",\n'
    '      dependencies: ["${className}Cpp"],\n'
    '      path: "Sources/$className"\n'
    '    )\n'
    '  ]\n'
    ')\n';
